517→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
518→        dropdown={
519→          <SearchDropdown
520→            sections={FILTER_SECTIONS}
521→            value={filterValue}
522→            onChange={handleFilterChange}
523→          />
524→        }
525→      />
526→      <div className="command-palette__body">
527→        <div className="command-palette__list-container">
528→          {totalItemCount === 0 ? (
529→            <EmptyState
530→              icon={<SearchEmptyIcon />}
531→              title="No Results"
532→              description="Try a different search term"
533→            />
534→          ) : (
535→            <List
536→              itemCount={totalItemCount}
537→              onActiveIndexChange={handleActiveIndexChange}
538→              onAction={handleAction}
539→            >
540→              {(() => {
541→                let globalIndex = 0;
542→
543→                const sections: ReactNode[] = [];
544→
545→                if (pinnedItems.length > 0) {
