556→                            subtitle={entry.sourceApp}
557→                            accessories={[
558→                              {
559→                                text: formatRelativeDate(entry.copiedAt, now),
560→                                tooltip: entry.copiedAt.toLocaleString(),
561→                              },
562→                            ]}
563→                            query={query || undefined}
564→                          />
565→                        );
566→                      })}
567→                    </ListSection>,
568→                  );
569→                }
570→
571→                if (recentItems.length > 0) {
572→                  sections.push(
573→                    <ListSection key="recent" title="Recent">
574→                      {recentItems.map(entry => {
575→                        const idx = globalIndex++;
576→                        return (
577→                          <ListItem
578→                            key={entry.id}
579→                            index={idx}
580→                            icon={renderClipboardIcon(entry)}
581→                            title={truncateContent(entry.content, 60)}
582→                            subtitle={entry.sourceApp}
583→                            accessories={[
584→                              {
585→                                text: formatRelativeDate(entry.copiedAt, now),
586→                                tooltip: entry.copiedAt.toLocaleString(),
587→                              },
588→                            ]}
589→                            query={query || undefined}
590→                          />
591→                        );
592→                      })}
593→                    </ListSection>,
594→                  );
595→                }
596→
597→                return sections;
598→              })()}
