605→        actions={[
606→          {
607→            label: 'Paste',
608→            shortcut: <Kbd keys={['↵']} />,
609→          },
610→          {
611→            label: 'Actions',
612→            shortcut: (
613→              <Kbd
614→                keys={[
615→                  '⌘',
616→                  'K',
617→                ]}
